def checkout_process(user, cart_items, discount_code, payment_info):
    # (1) Validate Cart Items
    def validate_cart_items(cart_items):
        if not cart_items:
            raise ValueError("Cart is empty.")
        for item in cart_items:
            if item['quantity'] <= 0:
                raise ValueError(f"Invalid quantity for item: {item['name']}.")
        return True

    # (2) Apply Discount Codes
    def apply_discount(user, discount_code, total_amount):
        discount_db = {
            "WELCOME10": {"discount": 0.10, "permit": "all"},
            "VIP20": {"discount": 0.20, "permit": "vip"},
            "ADMIN15": {"discount": 0.15, "permit": "admin"}
        }
        if discount_code in discount_db:
            discount_details = discount_db[discount_code]
            if discount_details["permit"] == "all" or discount_details["permit"] == user['tier']:
                return total_amount * (1 - discount_details["discount"])
            else:
                raise PermissionError("User doesn't have permission to use this discount code.")
        return total_amount

    # (3) Calculate Tax
    def calculate_tax(amount):
        TAX_RATE = 0.08
        return amount * TAX_RATE

    # (4) Process Payment
    def process_payment(payment_info, amount_to_pay):
        if payment_info['type'] == 'credit':
            if payment_info['balance'] >= amount_to_pay:
                payment_info['balance'] -= amount_to_pay
                return True
            else:
                raise ValueError("Insufficient funds.")
        else:
            raise ValueError("Unsupported payment type.")

    # (5) Create Order Record
    def create_order_record(user, cart_items, amount_paid, tax_amount):
        order_record = {
            "user_id": user['id'],
            "items": cart_items,
            "total_amount": amount_paid,
            "tax": tax_amount,
            "status": "completed"
        }
        return order_record

    # Perform Checkout Steps
    validate_cart_items(cart_items)
    total_amount = sum(item['price'] * item['quantity'] for item in cart_items)
    total_amount_after_discount = apply_discount(user, discount_code, total_amount)
    tax_amount = calculate_tax(total_amount_after_discount)
    amount_to_pay = total_amount_after_discount + tax_amount
    if process_payment(payment_info, amount_to_pay):
        return create_order_record(user, cart_items, amount_to_pay, tax_amount)

# Example Usage
